const data = $json.query;

return [{
  json: {
    threadId: data.id,
    originalMessageId: data.original_message_id,
    originalSenderPhone: data.sender_phone,
    replyFromPhone: data.recipient_phone.replace('+', ''),
    replyContent: data.current_message,
    replyMessageId: data.current_message_id,
    agentId: data.agent_id,
    userId: data.user_id,
    originalConversationId: data.original_conversation_id,
    currentConversationId: data.original_conversation_id, // Using original since current isn't in the data
    originalMessage: data.original_message
  }
}];

const data = $('Process Reply').item.json;

const notificationMessage = `📬 *Reply Received*

From: ${data.replyFromPhone}
Reply: "${data.replyContent}"

Original message: **"${data.originalMessage || 'N/A'}"**
Received at: ${new Date().toLocaleString()}`;

return [{
  json: {
    numbers: data.originalSenderPhone,  // ✅ Changed from originalSenderPhone
    message: notificationMessage,
    messageType: 'TEXT',
    agentId: data.agentId
  }
}];

const data = $('Process Reply').item.json;

const confirmationMessage = `✅ *Reply Acknowledged*

Your message has been delivered to the sender.
Thank you for your response!`;

return [{
  json: {
    numbers: data.replyFromPhone,
    message: confirmationMessage,
    messageType: 'TEXT',
    agentId: data.agentId
  }
}];

// Get data from the Format Reply Notification node which has the contact info
const formatData = $('Format Reply Notification to User').first().json;
const processData = $('Process Reply').first().json;

return [{
  json: {
    success: true,
    message: `✅ Reply notification sent successfully to original sender`,
    details: {
      threadId: processData.threadId,
      originalSender: processData.originalSenderPhone,
      replyFrom: processData.replyFromPhone,
      replyContent: processData.replyContent,
      status: 'notification_sent',
      timestamp: new Date().toISOString()
    }
  }
}];

